} from '../screens/MyOrdersDetails/utils';
import { STATUS_COLORS } from '../screens/MyOrdersDetails/Models';
import type { MarketplaceContentData, MarketplaceItemData } from '../screens/MyOrdersDetails/Models';
import { moment } from '../services/moment';

const MOCK_VOUCHER_AVAILABLE: PointsTransaction = {
