const MOCK_MARKETPLACE_ORDER: PointsTransaction = {
  id: 'MKT-20260210-005',
  date: '2026-02-10T12:00:00Z',
  description: 'Pedido Marketplace',
  type: 'RESCUE',
  amount: 8500,
  currencyValue: 85.0,
  icon: 'icon-shopping-cart',
  details: {
    provider: 'Marketplace Sem Parar',
    extraInfo: '',
