  },
  status: 'Enviado',
  marketplace: {
    orders: [
      {
        vendor: 'Loja Eletrônicos SP',
        items: [
          { name: 'Fone Bluetooth JBL', quantity: 1, valuePoints: 5000, imageUrl: undefined },
          { name: 'Carregador Portátil', quantity: 2, valuePoints: 1750, imageUrl: undefined },
        ],
      },
    ],
    payments: [{ paymentType: 'POINTS' }],
    shippingValuePoints: 0,
    valuePoints: 8500,
  },
};

const VARIANTS_MAP: Record<string, PointsTransaction> = {
  'Voucher Disponível': MOCK_VOUCHER_AVAILABLE,
  'Voucher Usado': MOCK_VOUCHER_USED,
  'Voucher Expirado': MOCK_VOUCHER_EXPIRED,
  'Cashback (Fatura)': MOCK_CASHBACK_ORDER,
  'Marketplace Order': MOCK_MARKETPLACE_ORDER,
};

function Divider() {
